mapper.select:
SELECT b.batch_id, b.create_time, b.update_time, b.status, b.original_filename, b.message, b.file_count, CASE b.status WHEN 0 THEN '处理中' WHEN 1 THEN '已处理' WHEN 2 THEN '处理失败' ELSE '未知' END AS status_desc, COUNT(m.batch_id) AS data_count FROM haosen_project..hr_batch b LEFT JOIN haosen_project..hr_monitoring_data m ON b.batch_id = m.batch_id
AND b.batch_id = #{condition.batchId}
AND b.status = #{condition.status}
AND b.create_time >= #{condition.startTime}
AND b.create_time <= #{condition.endTime}
GROUP BY b.batch_id, b.create_time, b.update_time, b.status, b.original_filename, b.message, b.file_count ORDER BY b.create_time DESC

mapper.update:
UPDATE haosen_project..hr_batch
SET status = #{status}, update_time = GETDATE()
WHERE batch_id = #{batchId}

UPDATE haosen_project..hr_batch
SET status = #{status}, message = #{message}, update_time = GETDATE()
WHERE batch_id = #{batchId}

UPDATE haosen_project..hr_batch
SET file_count = #{fileCount}, update_time = GETDATE()
WHERE batch_id = #{batchId}
